class PIIEncryptor:
    def __init__(self, encryption_key: Optional[bytes] = None):
        if encryption_key is None:
            encryption_key = os.environ.get('PII_ENCRYPTION_KEY')
            if encryption_key:
                encryption_key = encryption_key.encode()
            else:
                raise ValueError("Encryption key must be provided via parameter or PII_ENCRYPTION_KEY environment variable")
        
        if isinstance(encryption_key, str):
            encryption_key = encryption_key.encode()
            
        self.cipher = Fernet(encryption_key)
    
    def encrypt(self, data: str) -> str:
        if not data:
            return data
        encrypted = self.cipher.encrypt(data.encode())
        return encrypted.decode()
    
    def decrypt(self, encrypted_data: str) -> str:
        if not encrypted_data:
            return encrypted_data
        decrypted = self.cipher.decrypt(encrypted_data.encode())
        return decrypted.decode()


class SecureSQSPublisher:
    PII_FIELDS = ['email', 'phone_number', 'address', 'ssn', 'credit_card']
    
    def __init__(
        self,
        queue_url: str,
        encryption_key: Optional[bytes] = None,
        region_name: str = 'us-east-1',
        enable_encryption: bool = True,
        enable_audit_logging: bool = True
    ):
        self.queue_url = queue_url
        self.enable_encryption = enable_encryption
        self.enable_audit_logging = enable_audit_logging
        
        self.sqs_client = boto3.client(
            'sqs',
            region_name=region_name,
            config=boto3.session.Config(
                signature_version='s3v4',
                retries={'max_attempts': 3, 'mode': 'standard'}
            )
        )
        
        if self.enable_encryption:
            self.encryptor = PIIEncryptor(encryption_key)
        
        self._validate_queue_encryption()
    
    def _validate_queue_encryption(self):
        try:
            response = self.sqs_client.get_queue_attributes(
                QueueUrl=self.queue_url,
                AttributeNames=['KmsMasterKeyId', 'SqsManagedSseEnabled']
            )
            
            attributes = response.get('Attributes', {})
            has_kms = 'KmsMasterKeyId' in attributes
            has_sse = attributes.get('SqsManagedSseEnabled') == 'true'
            
            if not (has_kms or has_sse):
                logger.warning("Queue does not have server-side encryption enabled. Consider enabling SSE or KMS encryption.")
        except ClientError as e:
            logger.error(f"Failed to validate queue encryption: {e}")
    
    def _sanitize_for_logging(self, data: Dict[str, Any]) -> Dict[str, Any]:
        sanitized = {}
        for key, value in data.items():
            if key in self.PII_FIELDS:
                if value:
                    sanitized[key] = self._hash_pii(str(value))
                else:
                    sanitized[key] = None
            elif isinstance(value, dict):
                sanitized[key] = self._sanitize_for_logging(value)
            elif isinstance(value, list):
                sanitized[key] = [
                    self._sanitize_for_logging(item) if isinstance(item, dict) else item
                    for item in value
                ]
            else:
                sanitized[key] = value
        return sanitized
    
    def _hash_pii(self, value: str) -> str:
        salt = os.environ.get('PII_HASH_SALT', 'default-salt-change-me')
        return hmac.new(
            salt.encode(),
            value.encode(),
            hashlib.sha256
        ).hexdigest()[:16] + '...'
    
    def _encrypt_pii_fields(self, data: Dict[str, Any]) -> Dict[str, Any]:
        encrypted_data = data.copy()
        
        for field in self.PII_FIELDS:
            if field in encrypted_data and encrypted_data[field]:
                encrypted_data[field] = self.encryptor.encrypt(str(encrypted_data[field]))
        
        for key, value in encrypted_data.items():
            if isinstance(value, dict):
                encrypted_data[key] = self._encrypt_pii_fields(value)
            elif isinstance(value, list):
                encrypted_data[key] = [
                    self._encrypt_pii_fields(item) if isinstance(item, dict) else item
                    for item in value
                ]
        
        return encrypted_data
    
    def _validate_user_data(self, user_data: Dict[str, Any]) -> bool:
        if not isinstance(user_data, dict):
            raise ValueError("User data must be a dictionary")
        
        if 'user_id' not in user_data:
            raise ValueError("User data must contain 'user_id' field")
        
        return True
    
    def _create_message_body(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        message = {
            'timestamp': datetime.utcnow().isoformat(),
            'message_version': '1.0',
            'encrypted': self.enable_encryption,
            'data': user_data
        }
        return message
    
    def publish_user_data(
        self,
        user_data: Dict[str, Any],
        message_group_id: Optional[str] = None,
        deduplication_id: Optional[str] = None,
        message_attributes: Optional[Dict[str, Any]] = None
    ) -> Dict[str, Any]:
        try:
            self._validate_user_data(user_data)
            
            processed_data = user_data.copy()
            
            if self.enable_encryption:
                processed_data = self._encrypt_pii_fields(processed_data)
            
            message_body = self._create_message_body(processed_data)
            
            send_params = {
                'QueueUrl': self.queue_url,
                'MessageBody': json.dumps(message_body)
            }
            
            if message_attributes:
                formatted_attributes = {}
                for key, value in message_attributes.items():
                    if isinstance(value, str):
                        formatted_attributes[key] = {
                            'StringValue': value,
                            'DataType': 'String'
                        }
                    elif isinstance(value, (int, float)):
                        formatted_attributes[key] = {
                            'StringValue': str(value),
                            'DataType': 'Number'
                        }
                send_params['MessageAttributes'] = formatted_attributes
            
            if message_group_id:
                send_params['MessageGroupId'] = message_group_id
            
            if deduplication_id:
                send_params['MessageDeduplicationId'] = deduplication_id
            
            response = self.sqs_client.send_message(**send_params)
            
            if self.enable_audit_logging:
                sanitized_data = self._sanitize_for_logging(user_data)
                logger.info(
                    f"Published message - MessageId: {response['MessageId']}, "
                    f"User: {sanitized_data.get('user_id')}, "
                    f"Encrypted: {self.enable_encryption}"
                )
            
            return {
                'success': True,
                'message_id': response['MessageId'],
                'md5_of_body': response['MD5OfMessageBody'],
                'timestamp': datetime.utcnow().isoformat()
            }
            
        except ClientError as e:
            logger.error(f"Failed to publish message to SQS: {e}")
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }
        except Exception as e:
            logger.error(f"Unexpected error publishing message: {e}")
            return {
                'success': False,
                'error': str(e)
            }
    
    def publish_batch(
        self,
        user_data_list: list[Dict[str, Any]],
        message_group_id: Optional[str] = None
    ) -> Dict[str, Any]:
        if len(user_data_list) > 10:
            raise ValueError("Batch size cannot exceed 10 messages")
        
        entries = []
        for idx, user_data in enumerate(user_data_list):
            try:
                self._validate_user_data(user_data)
                
                processed_data = user_data.copy()
                if self.enable_encryption:
                    processed_data = self._encrypt_pii_fields(processed_data)
                
                message_body = self._create_message_body(processed_data)
                
                entry = {
                    'Id': str(idx),
                    'MessageBody': json.dumps(message_body)
                }
                
                if message_group_id:
                    entry['MessageGroupId'] = message_group_id
                    entry['MessageDeduplicationId'] = f"{message_group_id}-{idx}-{datetime.utcnow().timestamp()}"
                
                entries.append(entry)
                
            except Exception as e:
                logger.error(f"Failed to process message {idx}: {e}")
                continue
        
        if not entries:
            return {
                'success': False,
                'error': 'No valid messages to send'
            }
        
        try:
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries
            )
            
            successful = response.get('Successful', [])
            failed = response.get('Failed', [])
            
            if self.enable_audit_logging:
                logger.info(
                    f"Batch publish completed - Successful: {len(successful)}, "
                    f"Failed: {len(failed)}, Encrypted: {self.enable_encryption}"
                )
            
            return {
                'success': len(failed) == 0,
                'successful_count': len(successful),
                'failed_count': len(failed),
                'successful': successful,
                'failed': failed
            }
            
        except ClientError as e:
            logger.error(f"Failed to publish batch to SQS: {e}")
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }


